from bpmn_lang import Process, StartEvent, Task, EndEvent, SequenceFlow

start = StartEvent("start_event", "Start")
submit = Task("submit_request", "Submit Request")
end = EndEvent("end_event", "End")

process = Process({
    'start_events': [start],
    'tasks': [submit],
    'end_events': [end],
    'sequence_flows': [SequenceFlow(start, submit), SequenceFlow(submit, end)]
})
